// O(n^2 * 1000)
short dp[505][505];
bool vis[2005];
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var sum = vector<int>();
	fa(i, 1, n)fa(j, i, n) {
		int now = a[i] + a[j];
		if (!vis[now]) {
			vis[now] = 1;
			sum.pb(now);
		}
	}

	int ans = 1;
	if (n >= 2)ans = 2;
	for (int k : sum) {
		fa(i, 1, n)fa(j, 1, n)dp[i][j] = 0;
		fa(i, 1, n)if (a[i] * 2 == k)dp[i][i] = 1;
		fa(len, 2, n)fa(i, 1, n) {
			int j = i + len - 1;
			if (j > n)break;
			int now = a[i] + a[j];

          	// 注意这里，如果当前不等于 k，也不能直接跳，得继承上一维
			if (now == k)dp[i][j] = dp[i + 1][j - 1] + 2;
			else dp[i][j] = max(dp[i + 1][j], dp[i][j - 1]);

			ans = max(ans, (int)dp[i][j]);
		}
		vis[k] = 0;
	}
	cout << ans << endl;
	return;
}

// O(n^3)
short dp[505][505], mx[2005];
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	int ans = 1;
	fa(i, 1, n)dp[i][i] = 1;
	fb(i, n, 1) { // 左端点
		// mx[S]：记录当前可用区间 (i, j) 内部，和为 S 的 dp[x][y] 的最大值
		// 下面的枚举相当于把 (i, j) 内部的区间全考虑到了
		fa(j, i + 1, n) { // 右端点
			fa(k, i + 1, j - 1) {
				int now = a[k] + a[j - 1];
				mx[now] = max(mx[now], dp[k][j - 1]);
			}
			int now = a[i] + a[j];
			dp[i][j] = mx[now] + 2;
			ans = max(ans, (int)dp[i][j]);
		}
		fa(k, 0, 2000)mx[k] = 0;
	}
	cout << ans << endl;
	fa(i, 1, n)fa(j, 1, n)dp[i][j] = 0;
	return;
}
